class Solution {
    int[][] grid;
    int m, n;

    public Solution(int m, int n) {
        this.m = m;
        this.n = n;
        grid = new int[m][n];
    }

    public int[] flip() {
        int randRow = (int)(Math.random() * (m + 1));
        int randCol = (int)(Math.random() * (n + 1));
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                if (grid[randRow][randCol] == 0) {
                    grid[randRow][randCol] = 1;
                    return new int[]{randRow, randCol};
            }
        }
    }

    public void reset() {
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                grid[i][j] = 0;
            }
        }
    }
}
